{
  "name": "Smart Quiz Crafter",
  "description": "An intelligent exam generator that transforms your study materials into structured quizzes including multiple-choice, true/false, fill-in-the-blanks, and short answer questions."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum QuestionType {
  MULTIPLE_CHOICE = 'MULTIPLE_CHOICE',
  JUDGEMENT = 'JUDGEMENT',
  FILL_IN_BLANK = 'FILL_IN_BLANK',
  SHORT_ANSWER = 'SHORT_ANSWER'
}

export interface MultipleChoiceQuestion {
  question: string;
  options: string[];
  answer: string;
  explanation: string;
}

export interface JudgementQuestion {
  question: string;
  answer: boolean;
  explanation: string;
}

export interface FillInBlankQuestion {
  question: string;
  answer: string;
  explanation: string;
}

export interface ShortAnswerQuestion {
  question: string;
  sampleAnswer: string;
  keyPoints: string[];
}

export interface QuizSet {
  multipleChoice: MultipleChoiceQuestion[];
  judgement: JudgementQuestion[];
  fillInBlank: FillInBlankQuestion[];
  shortAnswer: ShortAnswerQuestion[];
}

export interface GenerationState {
  isGenerating: boolean;
  progress: number;
  message: string;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { QuizSet } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const QUIZ_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    multipleChoice: {
      type: Type.ARRAY,
      description: "Generate exactly 10 multiple-choice questions.",
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          options: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Exactly 4 options: A, B, C, D."
          },
          answer: { type: Type.STRING, description: "The correct option (e.g., 'A')" },
          explanation: { type: Type.STRING }
        },
        required: ["question", "options", "answer", "explanation"]
      }
    },
    judgement: {
      type: Type.ARRAY,
      description: "Generate exactly 10 true/false questions.",
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          answer: { type: Type.BOOLEAN },
          explanation: { type: Type.STRING }
        },
        required: ["question", "answer", "explanation"]
      }
    },
    fillInBlank: {
      type: Type.ARRAY,
      description: "Generate exactly 7 fill-in-the-blank questions.",
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING, description: "Question text with '____' for the blank." },
          answer: { type: Type.STRING },
          explanation: { type: Type.STRING }
        },
        required: ["question", "answer", "explanation"]
      }
    },
    shortAnswer: {
      type: Type.ARRAY,
      description: "Generate exactly 3 short-answer questions.",
      items: {
        type: Type.OBJECT,
        properties: {
          question: { type: Type.STRING },
          sampleAnswer: { type: Type.STRING },
          keyPoints: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "Main concepts required in the answer."
          }
        },
        required: ["question", "sampleAnswer", "keyPoints"]
      }
    }
  },
  required: ["multipleChoice", "judgement", "fillInBlank", "shortAnswer"]
};

export const generateQuizFromMaterial = async (material: string): Promise<QuizSet> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Based on the following material, generate a comprehensive quiz. 
    Requirements:
    - Language: Chinese (Simplified)
    - Total Questions: 30
    - Multiple Choice: 10
    - Judgement (True/False): 10
    - Fill-in-the-blanks: 7
    - Short Answer: 3

    Material Content:
    ${material}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: QUIZ_SCHEMA,
      temperature: 0.7,
    },
  });

  const text = response.text;
  if (!text) {
    throw new Error("No response generated from the model.");
  }

  try {
    return JSON.parse(text) as QuizSet;
  } catch (error) {
    console.error("Failed to parse JSON response:", text);
    throw new Error("Generated content format was invalid.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className, 
  disabled, 
  ...props 
}) => {
  const baseStyles = "px-6 py-2.5 rounded-xl font-medium transition-all duration-200 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed transform active:scale-95";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-md hover:shadow-lg",
    secondary: "bg-emerald-600 text-white hover:bg-emerald-700 shadow-md",
    outline: "border-2 border-indigo-600 text-indigo-600 hover:bg-indigo-50",
    ghost: "text-gray-600 hover:bg-gray-100"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin h-5 w-5 text-current" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
        </svg>
      )}
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { QuizSet, QuestionType } from '../types';

interface QuizDisplayProps {
  quiz: QuizSet;
}

export const QuizDisplay: React.FC<QuizDisplayProps> = ({ quiz }) => {
  const [showAnswers, setShowAnswers] = useState(false);

  const renderSection = (title: string, questions: any[], type: QuestionType) => {
    if (questions.length === 0) return null;

    return (
      <div className="mb-12">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-indigo-500 pl-4">{title}</h3>
        <div className="space-y-6">
          {questions.map((q, idx) => (
            <div key={idx} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow">
              <div className="flex gap-4">
                <span className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center font-bold text-sm">
                  {idx + 1}
                </span>
                <div className="flex-grow">
                  <p className="text-gray-800 text-lg mb-4 font-medium leading-relaxed">{q.question}</p>

                  {type === QuestionType.MULTIPLE_CHOICE && (
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
                      {q.options.map((opt: string, i: number) => (
                        <div key={i} className="p-3 rounded-lg border border-gray-100 bg-gray-50 text-gray-700">
                          {opt}
                        </div>
                      ))}
                    </div>
                  )}

                  {showAnswers && (
                    <div className="mt-4 p-4 rounded-xl bg-emerald-50 border border-emerald-100 animate-fadeIn">
                      <p className="text-emerald-800 font-semibold mb-1">
                        答案: <span className="font-bold">{type === QuestionType.JUDGEMENT ? (q.answer ? '正确 (True)' : '错误 (False)') : q.answer || q.sampleAnswer}</span>
                      </p>
                      {q.explanation && (
                        <p className="text-emerald-700 text-sm italic">解析: {q.explanation}</p>
                      )}
                      {q.keyPoints && (
                        <div className="mt-2">
                          <p className="text-emerald-800 text-sm font-semibold">关键点:</p>
                          <ul className="list-disc list-inside text-emerald-700 text-sm">
                            {q.keyPoints.map((kp: string, kIdx: number) => (
                              <li key={kIdx}>{kp}</li>
                            ))}
                          </ul>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="max-w-4xl mx-auto py-10 px-4">
      <div className="flex justify-between items-center mb-10 bg-white p-6 rounded-2xl shadow-sm sticky top-4 z-10 border border-gray-100">
        <div>
          <h2 className="text-2xl font-extrabold text-gray-900">生成的测验</h2>
          <p className="text-gray-500">共 30 道题目</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => setShowAnswers(!showAnswers)}
            className={`px-6 py-2 rounded-xl font-medium transition-colors ${showAnswers ? 'bg-indigo-100 text-indigo-700' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
          >
            {showAnswers ? '隐藏答案' : '显示答案'}
          </button>
          <button 
            onClick={() => window.print()}
            className="px-6 py-2 rounded-xl border-2 border-gray-200 text-gray-600 font-medium hover:bg-gray-50 transition-colors"
          >
            打印测验
          </button>
        </div>
      </div>

      {renderSection("一、单项选择题 (10题)", quiz.multipleChoice, QuestionType.MULTIPLE_CHOICE)}
      {renderSection("二、判断题 (10题)", quiz.judgement, QuestionType.JUDGEMENT)}
      {renderSection("三、填空题 (7题)", quiz.fillInBlank, QuestionType.FILL_IN_BLANK)}
      {renderSection("四、简答题 (3题)", quiz.shortAnswer, QuestionType.SHORT_ANSWER)}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Button } from './components/Button';
import { QuizDisplay } from './components/QuizDisplay';
import { generateQuizFromMaterial } from './services/geminiService';
import { QuizSet, GenerationState } from './types';

const App: React.FC = () => {
  const [material, setMaterial] = useState('');
  const [quiz, setQuiz] = useState<QuizSet | null>(null);
  const [status, setStatus] = useState<GenerationState>({
    isGenerating: false,
    progress: 0,
    message: '等待输入资料...'
  });

  const loadingMessages = [
    "正在深度解析您的资料内容...",
    "正在构思具有挑战性的题目...",
    "正在核对题目答案的准确性...",
    "正在完善详细的解析说明...",
    "即将完成，正在进行最后的排版..."
  ];

  useEffect(() => {
    let interval: any;
    if (status.isGenerating) {
      let msgIdx = 0;
      interval = setInterval(() => {
        msgIdx = (msgIdx + 1) % loadingMessages.length;
        setStatus(prev => ({
          ...prev,
          message: loadingMessages[msgIdx],
          progress: Math.min(prev.progress + 15, 95)
        }));
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [status.isGenerating]);

  const handleGenerate = async () => {
    if (!material.trim() || material.length < 50) {
      alert('请输入至少 50 字的资料内容以保证题目质量。');
      return;
    }

    setStatus({
      isGenerating: true,
      progress: 10,
      message: loadingMessages[0]
    });

    try {
      const result = await generateQuizFromMaterial(material);
      setQuiz(result);
      setStatus({
        isGenerating: false,
        progress: 100,
        message: '生成成功！'
      });
    } catch (error: any) {
      setStatus({
        isGenerating: false,
        progress: 0,
        message: '生成失败',
        error: error.message || '未知错误'
      });
    }
  };

  const reset = () => {
    setQuiz(null);
    setMaterial('');
    setStatus({
      isGenerating: false,
      progress: 0,
      message: '等待输入资料...'
    });
  };

  return (
    <div className="min-h-screen bg-slate-50">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 py-6">
        <div className="max-w-6xl mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-200 shadow-lg">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">Smart Quiz Crafter</h1>
              <p className="text-sm text-gray-500 font-medium">智能AI题库生成器</p>
            </div>
          </div>
          {quiz && (
            <Button variant="outline" onClick={reset}>重新生成</Button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-12">
        {!quiz && !status.isGenerating && (
          <div className="max-w-3xl mx-auto animate-fadeIn">
            <div className="text-center mb-12">
              <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">
                将资料转化为全套考卷
              </h2>
              <p className="text-lg text-gray-600">
                只需粘贴学习资料，AI 将自动为您生成 30 道结构化题目：<br/>
                包含选择、判断、填空与简答，完美覆盖知识点。
              </p>
            </div>

            <div className="bg-white rounded-3xl shadow-xl shadow-gray-200/50 p-8 border border-gray-100">
              <label className="block text-sm font-bold text-gray-700 mb-3 ml-1 uppercase tracking-wider">
                输入您的学习资料
              </label>
              <textarea
                value={material}
                onChange={(e) => setMaterial(e.target.value)}
                placeholder="在此粘贴文章、教材、笔记或任何学习资料内容（建议 500-2000 字左右效果最佳）..."
                className="w-full h-80 p-5 rounded-2xl border-2 border-gray-100 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-50/50 outline-none transition-all resize-none text-gray-700 leading-relaxed placeholder:text-gray-400"
              />

              <div className="mt-8 flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex gap-6 text-sm text-gray-500 font-medium">
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-emerald-500"></span> 10 选择 + 10 判断
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-indigo-500"></span> 7 填空 + 3 简答
                  </div>
                </div>
                <Button 
                  onClick={handleGenerate} 
                  className="w-full md:w-auto h-14 px-12 text-lg shadow-xl"
                  disabled={material.length < 50}
                >
                  立即生成完整题库
                </Button>
              </div>
            </div>
          </div>
        )}

        {status.isGenerating && (
          <div className="max-w-2xl mx-auto py-20 text-center animate-pulse">
            <div className="relative inline-block mb-12">
              <div className="w-24 h-24 bg-indigo-100 rounded-3xl flex items-center justify-center animate-bounce">
                <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
            </div>
            <h2 className="text-3xl font-bold text-gray-900 mb-4">正在创作您的测验内容...</h2>
            <p className="text-gray-600 mb-10 text-lg">{status.message}</p>

            <div className="w-full bg-gray-200 rounded-full h-3 mb-4 overflow-hidden shadow-inner">
              <div 
                className="bg-indigo-600 h-full rounded-full transition-all duration-700 ease-out shadow-lg shadow-indigo-200"
                style={{ width: `${status.progress}%` }}
              ></div>
            </div>
            <p className="text-sm font-bold text-indigo-600 tracking-widest">{status.progress}% 完成</p>
          </div>
        )}

        {quiz && !status.isGenerating && (
          <QuizDisplay quiz={quiz} />
        )}

        {status.error && (
          <div className="max-w-md mx-auto mt-10 p-6 bg-red-50 border border-red-100 rounded-2xl text-center">
            <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
              <svg className="w-6 h-6 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
            </div>
            <h3 className="text-red-900 font-bold mb-2">生成出错</h3>
            <p className="text-red-700 text-sm mb-6">{status.error}</p>
            <Button onClick={reset} variant="primary" className="bg-red-600 hover:bg-red-700">重试</Button>
          </div>
        )}
      </main>

      <footer className="mt-auto py-12 border-t border-gray-200 text-center text-gray-400 text-sm">
        <p>© 2024 Smart Quiz Crafter. Powered by Gemini Flash 3.0</p>
      </footer>

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(10px); }
          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fadeIn {
          animation: fadeIn 0.6s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import * as pdfjsLib from 'pdfjs-dist';
import mammoth from 'mammoth';
import * as XLSX from 'xlsx';

// Set worker for PDF.js
pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

export const extractTextFromFile = async (file: File): Promise<string> => {
  const extension = file.name.split('.').pop()?.toLowerCase();

  switch (extension) {
    case 'pdf':
      return await parsePDF(file);
    case 'docx':
      return await parseWord(file);
    case 'xlsx':
    case 'xls':
      return await parseExcel(file);
    case 'txt':
      return await file.text();
    default:
      throw new Error('不支持的文件格式。请上传 PDF, Word, Excel 或 TXT 文件。');
  }
};

const parsePDF = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  let fullText = '';
  for (let i = 1; i <= pdf.numPages; i++) {
    const page = await pdf.getPage(i);
    const content = await page.getTextContent();
    const strings = content.items.map((item: any) => item.str);
    fullText += strings.join(' ') + '\n';
  }
  return fullText;
};

const parseWord = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const result = await mammoth.extractRawText({ arrayBuffer });
  return result.value;
};

const parseExcel = async (file: File): Promise<string> => {
  const arrayBuffer = await file.arrayBuffer();
  const workbook = XLSX.read(arrayBuffer, { type: 'array' });
  let fullText = '';
  workbook.SheetNames.forEach(sheetName => {
    const sheet = workbook.Sheets[sheetName];
    fullText += XLSX.utils.sheet_to_txt(sheet) + '\n';
  });
  return fullText;
};

import React, { useState } from 'react';
import { QuizSet, QuestionType } from '../types';
import { Button } from './Button';

interface InteractiveQuizProps {
  quiz: QuizSet;
  onReset: () => void;
}

export const InteractiveQuiz: React.FC<InteractiveQuizProps> = ({ quiz, onReset }) => {
  const [answers, setAnswers] = useState<Record<string, string | boolean>>({});
  const [isSubmitted, setIsSubmitted] = useState(false);
  const [score, setScore] = useState(0);

  const handleAnswerChange = (id: string, value: string | boolean) => {
    if (isSubmitted) return;
    setAnswers(prev => ({ ...prev, [id]: value }));
  };

  const calculateScore = () => {
    let currentScore = 0;

    // Grade Multiple Choice (10 points each)
    quiz.multipleChoice.forEach((q, idx) => {
      if (answers[`mc-${idx}`] === q.answer) currentScore += 1;
    });

    // Grade Judgement (10 points each)
    quiz.judgement.forEach((q, idx) => {
      if (answers[`jd-${idx}`] === q.answer) currentScore += 1;
    });

    // Grade Fill in the blank (Rough match, 10 points each)
    quiz.fillInBlank.forEach((q, idx) => {
      const userAns = (answers[`fb-${idx}`] as string || '').trim().toLowerCase();
      const correctAns = q.answer.trim().toLowerCase();
      if (userAns === correctAns) currentScore += 1;
    });

    // Short answer is not automatically scored here but listed
    setScore(currentScore);
    setIsSubmitted(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const totalPossible = quiz.multipleChoice.length + quiz.judgement.length + quiz.fillInBlank.length;

  return (
    <div className="max-w-4xl mx-auto py-10 px-4">
      {isSubmitted && (
        <div className="mb-8 bg-white p-8 rounded-3xl shadow-xl border-t-8 border-indigo-600 animate-fadeIn text-center">
          <h2 className="text-3xl font-extrabold text-gray-900 mb-2">测试完成！</h2>
          <div className="text-6xl font-black text-indigo-600 my-4">
            {score} <span className="text-2xl text-gray-400">/ {totalPossible}</span>
          </div>
          <p className="text-gray-600 mb-6">您的得分基于客观题（选择、判断、填空）。简答题请对照解析自我评估。</p>
          <div className="flex justify-center gap-4">
            <Button variant="outline" onClick={() => setIsSubmitted(false)}>修改答案</Button>
            <Button variant="primary" onClick={onReset}>生成新测验</Button>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center mb-10 bg-white p-6 rounded-2xl shadow-sm border border-gray-100 sticky top-4 z-10">
        <div>
          <h2 className="text-2xl font-extrabold text-gray-900">在线答题模式</h2>
          <p className="text-gray-500">共 30 道题 (客观题 {totalPossible} 道)</p>
        </div>
        {!isSubmitted && (
          <Button onClick={calculateScore} variant="primary">提交答案</Button>
        )}
      </div>

      {/* Multiple Choice Section */}
      <section className="mb-12">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-indigo-500 pl-4">一、单项选择题</h3>
        <div className="space-y-6">
          {quiz.multipleChoice.map((q, idx) => {
            const id = `mc-${idx}`;
            const isCorrect = isSubmitted && answers[id] === q.answer;
            const isWrong = isSubmitted && answers[id] !== undefined && answers[id] !== q.answer;

            return (
              <div key={id} className={`bg-white p-6 rounded-2xl border transition-all ${isCorrect ? 'border-emerald-500 bg-emerald-50/30' : isWrong ? 'border-red-500 bg-red-50/30' : 'border-gray-100'}`}>
                <p className="text-lg font-medium text-gray-800 mb-4">{idx + 1}. {q.question}</p>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {q.options.map((opt) => {
                    const optKey = opt.charAt(0); // Assuming options are "A. xxx"
                    const isSelected = answers[id] === optKey;
                    return (
                      <button
                        key={opt}
                        disabled={isSubmitted}
                        onClick={() => handleAnswerChange(id, optKey)}
                        className={`text-left p-4 rounded-xl border-2 transition-all ${
                          isSelected ? 'border-indigo-600 bg-indigo-50 text-indigo-700 font-bold' : 'border-gray-100 bg-gray-50 text-gray-600 hover:border-indigo-200'
                        }`}
                      >
                        {opt}
                      </button>
                    );
                  })}
                </div>
                {isSubmitted && (
                  <div className="mt-4 p-4 rounded-xl bg-white border border-gray-200 text-sm">
                    <p className="font-bold text-indigo-600 mb-1">正确答案: {q.answer}</p>
                    <p className="text-gray-600 italic">解析: {q.explanation}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </section>

      {/* Judgement Section */}
      <section className="mb-12">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-indigo-500 pl-4">二、判断题</h3>
        <div className="space-y-6">
          {quiz.judgement.map((q, idx) => {
            const id = `jd-${idx}`;
            const isCorrect = isSubmitted && answers[id] === q.answer;
            const isWrong = isSubmitted && answers[id] !== undefined && answers[id] !== q.answer;

            return (
              <div key={id} className={`bg-white p-6 rounded-2xl border transition-all ${isCorrect ? 'border-emerald-500 bg-emerald-50/30' : isWrong ? 'border-red-500 bg-red-50/30' : 'border-gray-100'}`}>
                <p className="text-lg font-medium text-gray-800 mb-4">{idx + 1}. {q.question}</p>
                <div className="flex gap-4">
                  {[true, false].map((val) => (
                    <button
                      key={val.toString()}
                      disabled={isSubmitted}
                      onClick={() => handleAnswerChange(id, val)}
                      className={`px-8 py-3 rounded-xl border-2 transition-all ${
                        answers[id] === val ? 'border-indigo-600 bg-indigo-50 text-indigo-700 font-bold' : 'border-gray-100 bg-gray-50 text-gray-600'
                      }`}
                    >
                      {val ? '正确' : '错误'}
                    </button>
                  ))}
                </div>
                {isSubmitted && (
                  <div className="mt-4 p-4 rounded-xl bg-white border border-gray-200 text-sm">
                    <p className="font-bold text-indigo-600 mb-1">正确答案: {q.answer ? '正确' : '错误'}</p>
                    <p className="text-gray-600 italic">解析: {q.explanation}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </section>

      {/* Fill in Blank Section */}
      <section className="mb-12">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-indigo-500 pl-4">三、填空题</h3>
        <div className="space-y-6">
          {quiz.fillInBlank.map((q, idx) => {
            const id = `fb-${idx}`;
            const isCorrect = isSubmitted && (answers[id] as string || '').trim().toLowerCase() === q.answer.trim().toLowerCase();
            const isWrong = isSubmitted && (answers[id] as string || '').trim().toLowerCase() !== q.answer.trim().toLowerCase();

            return (
              <div key={id} className={`bg-white p-6 rounded-2xl border transition-all ${isCorrect ? 'border-emerald-500 bg-emerald-50/30' : isWrong ? 'border-red-500 bg-red-50/30' : 'border-gray-100'}`}>
                <p className="text-lg font-medium text-gray-800 mb-4">{idx + 1}. {q.question}</p>
                <input
                  type="text"
                  disabled={isSubmitted}
                  value={answers[id] as string || ''}
                  onChange={(e) => handleAnswerChange(id, e.target.value)}
                  placeholder="请输入答案..."
                  className="w-full md:w-1/2 p-3 rounded-xl border-2 border-gray-100 focus:border-indigo-500 outline-none transition-all"
                />
                {isSubmitted && (
                  <div className="mt-4 p-4 rounded-xl bg-white border border-gray-200 text-sm">
                    <p className="font-bold text-indigo-600 mb-1">正确答案: {q.answer}</p>
                    <p className="text-gray-600 italic">解析: {q.explanation}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </section>

      {/* Short Answer Section */}
      <section className="mb-12">
        <h3 className="text-xl font-bold text-gray-800 mb-6 border-l-4 border-indigo-500 pl-4">四、简答题</h3>
        <div className="space-y-6">
          {quiz.shortAnswer.map((q, idx) => (
            <div key={`sa-${idx}`} className="bg-white p-6 rounded-2xl border border-gray-100">
              <p className="text-lg font-medium text-gray-800 mb-4">{idx + 1}. {q.question}</p>
              <textarea
                disabled={isSubmitted}
                placeholder="在此输入您的回答..."
                className="w-full h-32 p-4 rounded-xl border-2 border-gray-100 focus:border-indigo-500 outline-none transition-all resize-none"
              />
              {isSubmitted && (
                <div className="mt-4 p-6 rounded-xl bg-indigo-50 border border-indigo-100 animate-fadeIn">
                  <p className="font-bold text-indigo-900 mb-2">参考答案:</p>
                  <p className="text-indigo-800 mb-4 leading-relaxed">{q.sampleAnswer}</p>
                  <div>
                    <p className="text-indigo-900 text-sm font-bold mb-2">核心得分点:</p>
                    <ul className="list-disc list-inside space-y-1">
                      {q.keyPoints.map((kp, kIdx) => (
                        <li key={kIdx} className="text-indigo-700 text-sm">{kp}</li>
                      ))}
                    </ul>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      </section>

      {!isSubmitted && (
        <div className="mt-12 flex justify-center">
          <Button onClick={calculateScore} className="h-16 px-16 text-xl shadow-2xl">提交所有答案并评分</Button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Button } from './components/Button';
import { InteractiveQuiz } from './components/InteractiveQuiz';
import { generateQuizFromMaterial } from './services/geminiService';
import { extractTextFromFile } from './services/fileParser';
import { QuizSet, GenerationState } from './types';

const App: React.FC = () => {
  const [material, setMaterial] = useState('');
  const [quiz, setQuiz] = useState<QuizSet | null>(null);
  const [fileName, setFileName] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [status, setStatus] = useState<GenerationState>({
    isGenerating: false,
    progress: 0,
    message: '等待上传资料...'
  });

  const loadingMessages = [
    "正在深度解析您的资料内容...",
    "正在构思具有挑战性的题目...",
    "正在核对题目答案的准确性...",
    "正在完善详细的解析说明...",
    "即将完成，正在进行最后的排版..."
  ];

  useEffect(() => {
    let interval: any;
    if (status.isGenerating) {
      let msgIdx = 0;
      interval = setInterval(() => {
        msgIdx = (msgIdx + 1) % loadingMessages.length;
        setStatus(prev => ({
          ...prev,
          message: loadingMessages[msgIdx],
          progress: Math.min(prev.progress + 15, 95)
        }));
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [status.isGenerating]);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setStatus(prev => ({ ...prev, message: `正在读取: ${file.name}...` }));

    try {
      const text = await extractTextFromFile(file);
      if (text.trim().length < 50) {
        throw new Error('文件内容太短，无法生成高质量题目。');
      }
      setMaterial(text);
      setStatus(prev => ({ ...prev, message: '文件读取成功，点击生成开始！' }));
    } catch (err: any) {
      alert(err.message || '文件解析失败');
      setFileName(null);
    }
  };

  const handleGenerate = async () => {
    if (!material.trim()) {
      alert('请先上传文件。');
      return;
    }

    setStatus({
      isGenerating: true,
      progress: 10,
      message: loadingMessages[0]
    });

    try {
      const result = await generateQuizFromMaterial(material);
      setQuiz(result);
      setStatus({
        isGenerating: false,
        progress: 100,
        message: '生成成功！'
      });
    } catch (error: any) {
      setStatus({
        isGenerating: false,
        progress: 0,
        message: '生成失败',
        error: error.message || '未知错误'
      });
    }
  };

  const reset = () => {
    setQuiz(null);
    setMaterial('');
    setFileName(null);
    setStatus({
      isGenerating: false,
      progress: 0,
      message: '等待上传资料...'
    });
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white border-b border-gray-200 py-6">
        <div className="max-w-6xl mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-indigo-200 shadow-lg">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900">Smart Quiz Crafter Pro</h1>
              <p className="text-sm text-gray-500 font-medium">支持 PDF/Word/Excel 的 AI 考卷系统</p>
            </div>
          </div>
          {quiz && (
            <Button variant="outline" onClick={reset}>重新生成</Button>
          )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 py-12">
        {!quiz && !status.isGenerating && (
          <div className="max-w-3xl mx-auto animate-fadeIn">
            <div className="text-center mb-12">
              <h2 className="text-4xl font-extrabold text-gray-900 mb-4 tracking-tight">
                上传附件，开启智能测验
              </h2>
              <p className="text-lg text-gray-600">
                支持 PDF, Word (.docx), Excel (.xlsx) 及文本文档。<br/>
                AI 将为您提取核心知识点并生成包含评分系统的在线考卷。
              </p>
            </div>

            <div className="bg-white rounded-3xl shadow-xl shadow-gray-200/50 p-10 border border-gray-100">
              <div 
                onClick={() => fileInputRef.current?.click()}
                className={`group cursor-pointer border-4 border-dashed rounded-3xl p-12 text-center transition-all ${
                  fileName ? 'border-emerald-200 bg-emerald-50/50' : 'border-gray-100 hover:border-indigo-200 hover:bg-indigo-50/30'
                }`}
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleFileUpload}
                  className="hidden" 
                  accept=".pdf,.docx,.xlsx,.xls,.txt"
                />
                <div className="w-20 h-20 bg-white rounded-2xl shadow-sm flex items-center justify-center mx-auto mb-6 group-hover:scale-110 transition-transform">
                  <svg className={`w-10 h-10 ${fileName ? 'text-emerald-500' : 'text-indigo-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                  </svg>
                </div>
                {fileName ? (
                  <>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">{fileName}</h3>
                    <p className="text-emerald-600 font-medium">文件已准备就绪</p>
                  </>
                ) : (
                  <>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">点击或拖拽文件上传</h3>
                    <p className="text-gray-500">支持 PDF, DOCX, XLSX, TXT (最大 10MB)</p>
                  </>
                )}
              </div>

              <div className="mt-10 flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="grid grid-cols-2 gap-x-8 gap-y-2 text-sm text-gray-500 font-medium">
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-indigo-500"></span> 10道 单选题
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-emerald-500"></span> 10道 判断题
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-amber-500"></span> 7道 填空题
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-red-500"></span> 3道 简答题
                  </div>
                </div>
                <Button 
                  onClick={handleGenerate} 
                  className="w-full md:w-auto h-16 px-12 text-lg shadow-xl"
                  disabled={!material}
                >
                  开始生成考卷
                </Button>
              </div>
            </div>
          </div>
        )}

        {status.isGenerating && (
          <div className="max-w-2xl mx-auto py-20 text-center animate-pulse">
            <div className="relative inline-block mb-12">
              <div className="w-24 h-24 bg-indigo-100 rounded-3xl flex items-center justify-center animate-bounce">
                <svg className="w-12 h-12 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
